//#region src/functions/statistical/chisq-test/index.ts
var ChisqTest = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 2);
		_defineProperty(this, "maxParams", 2);
	}
	calculate(actualRange, expectedRange) {
		const actualRangeRowCount = actualRange.isArray() ? actualRange.getRowCount() : 1;
		const actualRangeColumnCount = actualRange.isArray() ? actualRange.getColumnCount() : 1;
		const expectedRangeRowCount = expectedRange.isArray() ? expectedRange.getRowCount() : 1;
		const expectedRangeColumnCount = expectedRange.isArray() ? expectedRange.getColumnCount() : 1;
		let _actualRange = actualRange;
		if (actualRange.isArray() && actualRangeRowCount === 1 && actualRangeColumnCount === 1) _actualRange = actualRange.get(0, 0);
		if (_actualRange.isError()) return _actualRange;
		let _expectedRange = expectedRange;
		if (expectedRange.isArray() && expectedRangeRowCount === 1 && expectedRangeColumnCount === 1) _expectedRange = expectedRange.get(0, 0);
		if (_expectedRange.isError()) return _expectedRange;
		if (actualRangeRowCount * actualRangeColumnCount === 1 || expectedRangeRowCount * expectedRangeColumnCount === 1) {
			if (_actualRange.isNull() || _expectedRange.isNull()) return ErrorValueObject.create("#VALUE!");
			return ErrorValueObject.create("#N/A");
		}
		if (actualRangeRowCount * actualRangeColumnCount !== expectedRangeRowCount * expectedRangeColumnCount) return ErrorValueObject.create("#N/A");
		const { isError, errorObject, array1Values, array2Values, noCalculate } = getTwoArrayNumberValues(actualRange, expectedRange, actualRangeRowCount * actualRangeColumnCount, actualRangeColumnCount, expectedRangeColumnCount);
		if (isError) return errorObject;
		if (noCalculate) return ErrorValueObject.create("#DIV/0!");
		return this._getResult(array1Values, array2Values, actualRangeRowCount, actualRangeColumnCount);
	}
	_getResult(actualRangeValues, expectedRangeValues, actualRangeRowCount, actualRangeColumnCount) {
		let sumxmy2 = 0;
		for (let i = 0; i < actualRangeValues.length; i++) {
			if (expectedRangeValues[i] === 0) return ErrorValueObject.create("#DIV/0!");
			sumxmy2 += (actualRangeValues[i] - expectedRangeValues[i]) ** 2 / expectedRangeValues[i];
		}
		let df = (actualRangeRowCount - 1) * (actualRangeColumnCount - 1);
		if (actualRangeRowCount === 1) df = actualRangeColumnCount - 1;
		else if (actualRangeColumnCount === 1) df = actualRangeRowCount - 1;
		const result = 1 - chisquareCDF(sumxmy2, df);
		return NumberValueObject.create(result);
	}
};

