var CovarianceP = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 2);
		_defineProperty(this, "maxParams", 2);
	}
	calculate(array1, array2) {
		const array1RowCount = array1.isArray() ? array1.getRowCount() : 1;
		const array1ColumnCount = array1.isArray() ? array1.getColumnCount() : 1;
		const array2RowCount = array2.isArray() ? array2.getRowCount() : 1;
		const array2ColumnCount = array2.isArray() ? array2.getColumnCount() : 1;
		let _array1 = array1;
		if (array1.isArray() && array1RowCount === 1 && array1ColumnCount === 1) _array1 = array1.get(0, 0);
		if (_array1.isError()) return _array1;
		let _array2 = array2;
		if (array2.isArray() && array2RowCount === 1 && array2ColumnCount === 1) _array2 = array2.get(0, 0);
		if (_array2.isError()) return _array2;
		if (array1RowCount * array1ColumnCount === 1 || array2RowCount * array2ColumnCount === 1) {
			if (_array1.isNull() || _array2.isNull()) return ErrorValueObject.create("#VALUE!");
		}
		if (array1RowCount * array1ColumnCount !== array2RowCount * array2ColumnCount) return ErrorValueObject.create("#N/A");
		const { isError, errorObject, array1Values, array2Values, noCalculate } = getTwoArrayNumberValues(array1, array2, array1RowCount * array1ColumnCount, array1ColumnCount, array2ColumnCount);
		if (isError) return errorObject;
		if (noCalculate) return ErrorValueObject.create("#DIV/0!");
		return this._getResult(array1Values, array2Values);
	}
	_getResult(array1Values, array2Values) {
		if (array1Values.length === 0) return ErrorValueObject.create("#DIV/0!");
		const n = array1Values.length;
		let array1Sum = 0;
		let array2Sum = 0;
		for (let i = 0; i < n; i++) {
			array1Sum += array1Values[i];
			array2Sum += array2Values[i];
		}
		const array1Mean = array1Sum / n;
		const array2Mean = array2Sum / n;
		let numerator = 0;
		for (let i = 0; i < n; i++) {
			const array1Diff = array1Values[i] - array1Mean;
			const array2Diff = array2Values[i] - array2Mean;
			numerator += array1Diff * array2Diff;
		}
		return NumberValueObject.create(numerator / n);
	}
};

