//#region src/functions/statistical/f-test/index.ts
var FTest = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 2);
		_defineProperty(this, "maxParams", 2);
	}
	calculate(array1, array2) {
		const { isError: isError_array1, errorObject: errorObject_array1, variance: variance_array1, ns1: ns1_array1 } = this._getValues(array1);
		if (isError_array1) return errorObject_array1;
		const { isError: isError_array2, errorObject: errorObject_array2, variance: variance_array2, ns1: ns1_array2 } = this._getValues(array2);
		if (isError_array2) return errorObject_array2;
		let result = 2 * (1 - centralFCDF(variance_array1 / variance_array2, ns1_array1, ns1_array2));
		if (result > 1) result = 2 - result;
		return NumberValueObject.create(result);
	}
	_getValues(array) {
		let variance = 0;
		let ns1 = 0;
		const arrayRowCount = array.isArray() ? array.getRowCount() : 1;
		const arrayColumnCount = array.isArray() ? array.getColumnCount() : 1;
		if (arrayRowCount === 1 && arrayColumnCount === 1) {
			const _array = array.isArray() ? array.get(0, 0) : array;
			if (_array.isError()) return {
				isError: true,
				errorObject: _array,
				variance,
				ns1
			};
			if (_array.isNull()) return {
				isError: true,
				errorObject: ErrorValueObject.create("#VALUE!"),
				variance,
				ns1
			};
			return {
				isError: true,
				errorObject: ErrorValueObject.create("#DIV/0!"),
				variance,
				ns1
			};
		}
		const values = [];
		let sum = 0;
		for (let r = 0; r < arrayRowCount; r++) for (let c = 0; c < arrayColumnCount; c++) {
			const valueObject = array.isArray() ? array.get(r, c) : array;
			if (valueObject.isError()) return {
				isError: true,
				errorObject: valueObject,
				variance,
				ns1
			};
			if (valueObject.isNull() || valueObject.isBoolean()) continue;
			const value = valueObject.getValue();
			if (!isRealNum(value)) continue;
			values.push(+value);
			sum += +value;
		}
		if (values.length <= 1) return {
			isError: true,
			errorObject: ErrorValueObject.create("#DIV/0!"),
			variance,
			ns1
		};
		const mean = sum / values.length;
		let sumSquares = 0;
		for (let i = 0; i < values.length; i++) sumSquares += (values[i] - mean) ** 2;
		ns1 = values.length - 1;
		variance = sumSquares / ns1;
		if (variance === 0) return {
			isError: true,
			errorObject: ErrorValueObject.create("#DIV/0!"),
			variance,
			ns1
		};
		return {
			isError: false,
			errorObject: null,
			variance,
			ns1
		};
	}
};

