//#region src/functions/statistical/mode-sngl/index.ts
var ModeSngl = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 1);
		_defineProperty(this, "maxParams", 255);
	}
	calculate(...variants) {
		const valueCountMap = {};
		let order = 0;
		let valueMaxCount = 1;
		for (let i = 0; i < variants.length; i++) {
			const variant = variants[i];
			if (variant.isError()) return variant;
			if (variant.isString()) {
				const _variant = variant.convertToNumberObjectValue();
				if (_variant.isError()) return _variant;
			}
			const rowCount = variant.isArray() ? variant.getRowCount() : 1;
			const columnCount = variant.isArray() ? variant.getColumnCount() : 1;
			for (let r = 0; r < rowCount; r++) for (let c = 0; c < columnCount; c++) {
				const valueObject = variant.isArray() ? variant.get(r, c) : variant;
				if (valueObject.isError()) return valueObject;
				if (valueObject.isNull() || valueObject.isBoolean() || valueObject.isString()) continue;
				const value = valueObject.getValue();
				if (!isRealNum(value)) continue;
				if (valueCountMap[+value]) {
					valueCountMap[+value].count++;
					if (valueCountMap[+value].count > valueMaxCount) valueMaxCount = valueCountMap[+value].count;
				} else valueCountMap[+value] = {
					count: 1,
					order: order++
				};
			}
		}
		if (order === 0 || valueMaxCount === 1) return new ErrorValueObject("#N/A");
		return getModeSnglResult(valueCountMap, valueMaxCount);
	}
};

