//#region src/functions/statistical/percentrank-inc/index.ts
var PercentrankInc = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 2);
		_defineProperty(this, "maxParams", 3);
	}
	calculate(array, x, significance) {
		const arrayValues = this._getValues(array);
		let _significance = significance !== null && significance !== void 0 ? significance : NumberValueObject.create(3);
		if (_significance.isNull()) _significance = NumberValueObject.create(3);
		const maxRowLength = Math.max(x.isArray() ? x.getRowCount() : 1, _significance.isArray() ? _significance.getRowCount() : 1);
		const maxColumnLength = Math.max(x.isArray() ? x.getColumnCount() : 1, _significance.isArray() ? _significance.getColumnCount() : 1);
		const xArray = expandArrayValueObject(maxRowLength, maxColumnLength, x, ErrorValueObject.create("#N/A"));
		const significanceArray = expandArrayValueObject(maxRowLength, maxColumnLength, _significance, ErrorValueObject.create("#N/A"));
		const resultArray = xArray.mapValue((xObject, rowIndex, columnIndex) => {
			const significanceObject = significanceArray.get(rowIndex, columnIndex);
			if (xObject.isError()) return xObject;
			if (significanceObject.isError()) return significanceObject;
			return this._handleSingleObject(arrayValues, xObject, significanceObject);
		});
		if (maxRowLength === 1 && maxColumnLength === 1) return resultArray.get(0, 0);
		return resultArray;
	}
	_handleSingleObject(array, x, significance) {
		if (array instanceof ErrorValueObject) return array;
		const { isError, errorObject, variants } = checkVariantsErrorIsStringToNumber(x, significance);
		if (isError) return errorObject;
		const [xObject, significanceObject] = variants;
		const xValue = +xObject.getValue();
		const significanceValue = Math.floor(+significanceObject.getValue());
		const n = array.length;
		if (n === 0 || xValue < array[0] || xValue > array[n - 1]) return ErrorValueObject.create("#N/A");
		if (n === 1) if (xValue === array[0]) return NumberValueObject.create(1);
		else return ErrorValueObject.create("#N/A");
		let result = 0;
		let match = false;
		let i = 0;
		while (!match && i < n) {
			if (xValue === array[i]) {
				result = i / (n - 1);
				match = true;
			} else if (xValue > array[i] && i + 1 < n && xValue < array[i + 1]) {
				result = (i + (xValue - array[i]) / (array[i + 1] - array[i])) / (n - 1);
				match = true;
			}
			i++;
		}
		if (!match) return ErrorValueObject.create("#N/A");
		if (significanceValue < 1) return ErrorValueObject.create("#NUM!");
		result = floor(result, significanceValue);
		return NumberValueObject.create(result);
	}
	_getValues(array) {
		const rowCount = array.isArray() ? array.getRowCount() : 1;
		const columnCount = array.isArray() ? array.getColumnCount() : 1;
		const values = [];
		for (let r = 0; r < rowCount; r++) for (let c = 0; c < columnCount; c++) {
			const valueObject = array.isArray() ? array.get(r, c) : array;
			if (valueObject.isError()) return valueObject;
			if (valueObject.isNull() || valueObject.isBoolean()) continue;
			const value = valueObject.getValue();
			if (!isRealNum(value)) continue;
			values.push(+value);
		}
		return values.sort((a, b) => a - b);
	}
};

