//#region src/functions/date/date/index.ts
var DateFunction = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 3);
		_defineProperty(this, "maxParams", 3);
	}
	calculate(year, month, day) {
		const maxRowLength = Math.max(year.isArray() ? year.getRowCount() : 1, month.isArray() ? month.getRowCount() : 1, day.isArray() ? day.getRowCount() : 1);
		const maxColumnLength = Math.max(year.isArray() ? year.getColumnCount() : 1, month.isArray() ? month.getColumnCount() : 1, day.isArray() ? day.getColumnCount() : 1);
		const yearArray = expandArrayValueObject(maxRowLength, maxColumnLength, year, ErrorValueObject.create("#N/A"));
		const monthArray = expandArrayValueObject(maxRowLength, maxColumnLength, month, ErrorValueObject.create("#N/A"));
		const dayArray = expandArrayValueObject(maxRowLength, maxColumnLength, day, ErrorValueObject.create("#N/A"));
		const resultArray = yearArray.map((yearObject, rowIndex, columnIndex) => {
			const monthObject = monthArray.get(rowIndex, columnIndex);
			const dayObject = dayArray.get(rowIndex, columnIndex);
			if (yearObject.isError()) return yearObject;
			if (monthObject.isError()) return monthObject;
			if (dayObject.isError()) return dayObject;
			const { isError, errorObject, variants } = checkVariantsErrorIsStringToNumber(yearObject, monthObject, dayObject);
			if (isError) return errorObject;
			const [_yearObject, _monthObject, _dayObject] = variants;
			let yearValue = Math.floor(+_yearObject.getValue());
			const monthValue = Math.floor(+_monthObject.getValue());
			const dayValue = Math.floor(+_dayObject.getValue());
			if (yearValue < 0 || yearValue > 9999) return ErrorValueObject.create("#NUM!");
			if (yearValue >= 0 && yearValue < 1899) yearValue += 1900;
			const currentSerial = excelDateSerial(new Date(Date.UTC(yearValue, monthValue - 1, dayValue)));
			if (currentSerial < 0) return ErrorValueObject.create("#NUM!");
			return NumberValueObject.create(currentSerial, DEFAULT_DATE_FORMAT);
		});
		if (maxRowLength === 1 && maxColumnLength === 1) return resultArray.get(0, 0);
		return resultArray;
	}
};

