//#region src/functions/date/datevalue/index.ts
var Datevalue = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 1);
		_defineProperty(this, "maxParams", 1);
	}
	isArgumentsIgnoreNumberPattern() {
		return true;
	}
	calculate(dateText) {
		if (dateText.isArray()) return dateText.mapValue((dateTextObject) => this._handleSingleObject(dateTextObject));
		return this._handleSingleObject(dateText);
	}
	_handleSingleObject(dateTextObject) {
		if (dateTextObject.isError()) return dateTextObject;
		if (dateTextObject.isString()) {
			const value = `${dateTextObject.getValue()}`;
			let parsedDate = parseFormattedDate(value);
			if (parsedDate === null) parsedDate = parseFormattedTime(value);
			if (parsedDate) {
				let { v, z } = parsedDate;
				if (z && isDate(z)) {
					if (v instanceof Date) v = excelDateTimeSerial(v);
					return NumberValueObject.create(Math.trunc(+v));
				}
			}
		}
		return ErrorValueObject.create("#VALUE!");
	}
};

