//#region src/functions/date/day/index.ts
var Day = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 1);
		_defineProperty(this, "maxParams", 1);
	}
	calculate(serialNumber) {
		if (serialNumber.isError()) return serialNumber;
		if (serialNumber.isArray()) return serialNumber.map((serialNumberObject) => this._handleSingleObject(serialNumberObject));
		return this._handleSingleObject(serialNumber);
	}
	_handleSingleObject(serialNumberObject) {
		let date;
		const dateValue = serialNumberObject.getValue();
		if (serialNumberObject.isString()) {
			if (!isValidDateStr(`${dateValue}`)) return ErrorValueObject.create("#VALUE!");
			date = /* @__PURE__ */ new Date(`${dateValue}`);
		} else {
			const dateSerial = +serialNumberObject.getValue();
			if (dateSerial < 0) return ErrorValueObject.create("#NUM!");
			if (dateSerial === 0) return NumberValueObject.create(0);
			date = excelSerialToDate(dateSerial);
		}
		const day = date.getUTCDate();
		return NumberValueObject.create(day);
	}
};

