//#region src/functions/date/days/index.ts
var Days = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 2);
		_defineProperty(this, "maxParams", 2);
	}
	calculate(endDate, startDate) {
		if (endDate.isError()) return endDate;
		if (startDate.isError()) return startDate;
		const maxRowLength = Math.max(endDate.isArray() ? endDate.getRowCount() : 1, startDate.isArray() ? startDate.getRowCount() : 1);
		const maxColumnLength = Math.max(endDate.isArray() ? endDate.getColumnCount() : 1, startDate.isArray() ? startDate.getColumnCount() : 1);
		const endDateArray = expandArrayValueObject(maxRowLength, maxColumnLength, endDate);
		const startDateArray = expandArrayValueObject(maxRowLength, maxColumnLength, startDate);
		const resultArray = endDateArray.map((endDateObject, rowIndex, columnIndex) => {
			const startDateObject = startDateArray.get(rowIndex, columnIndex);
			if (endDateObject.isError()) return endDateObject;
			if (startDateObject.isError()) return startDateObject;
			const endDateSerialNumber = getDateSerialNumberByObject(endDateObject);
			if (typeof endDateSerialNumber !== "number") return endDateSerialNumber;
			const startDateSerialNumber = getDateSerialNumberByObject(startDateObject);
			if (typeof startDateSerialNumber !== "number") return startDateSerialNumber;
			const result = Math.floor(endDateSerialNumber) - Math.floor(startDateSerialNumber);
			return NumberValueObject.create(result);
		});
		if (maxRowLength === 1 && maxColumnLength === 1) return resultArray.get(0, 0);
		return resultArray;
	}
};

