var ConfidenceT = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 3);
		_defineProperty(this, "maxParams", 3);
	}
	calculate(alpha, standardDev, size) {
		const maxRowLength = Math.max(alpha.isArray() ? alpha.getRowCount() : 1, standardDev.isArray() ? standardDev.getRowCount() : 1, size.isArray() ? size.getRowCount() : 1);
		const maxColumnLength = Math.max(alpha.isArray() ? alpha.getColumnCount() : 1, standardDev.isArray() ? standardDev.getColumnCount() : 1, size.isArray() ? size.getColumnCount() : 1);
		const alphaArray = expandArrayValueObject(maxRowLength, maxColumnLength, alpha, ErrorValueObject.create("#N/A"));
		const standardDevArray = expandArrayValueObject(maxRowLength, maxColumnLength, standardDev, ErrorValueObject.create("#N/A"));
		const sizeArray = expandArrayValueObject(maxRowLength, maxColumnLength, size, ErrorValueObject.create("#N/A"));
		const resultArray = alphaArray.mapValue((alphaObject, rowIndex, columnIndex) => {
			const standardDevObject = standardDevArray.get(rowIndex, columnIndex);
			const sizeObject = sizeArray.get(rowIndex, columnIndex);
			if (alphaObject.isError()) return alphaObject;
			if (standardDevObject.isError()) return standardDevObject;
			if (sizeObject.isError()) return sizeObject;
			const { isError, errorObject, variants } = checkVariantsErrorIsStringToNumber(alphaObject, standardDevObject, sizeObject);
			if (isError) return errorObject;
			const [_alphaObject, _standardDevObject, _sizeObject] = variants;
			const alphaValue = +_alphaObject.getValue();
			const standardDevValue = +_standardDevObject.getValue();
			const sizeValue = Math.floor(+_sizeObject.getValue());
			if (alphaValue <= 0 || alphaValue >= 1 || standardDevValue <= 0 || sizeValue < 1) return ErrorValueObject.create("#NUM!");
			if (sizeValue === 1) return ErrorValueObject.create("#DIV/0!");
			const result = Math.abs(studentTINV(alphaValue / 2, sizeValue - 1) * standardDevValue / Math.sqrt(sizeValue));
			return NumberValueObject.create(result);
		});
		if (maxRowLength === 1 && maxColumnLength === 1) return resultArray.get(0, 0);
		return resultArray;
	}
};

