//#region src/functions/statistical/count/index.ts
var Count = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 1);
		_defineProperty(this, "maxParams", 255);
	}
	calculate(...variants) {
		let accumulatorAll = NumberValueObject.create(0);
		for (let i = 0; i < variants.length; i++) {
			const variant = variants[i];
			if (variant.isError()) continue;
			if (variant.isArray()) accumulatorAll = accumulatorAll.plus(variant.count());
			else if (variant.isString()) {
				if (!variant.convertToNumberObjectValue().isError()) accumulatorAll = accumulatorAll.plus(NumberValueObject.create(1));
			} else if (!variant.isNull()) accumulatorAll = accumulatorAll.plus(NumberValueObject.create(1));
		}
		return accumulatorAll;
	}
};

