//#region src/functions/statistical/countif/index.ts
var Countif = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 2);
		_defineProperty(this, "maxParams", 2);
		_defineProperty(this, "needsReferenceObject", true);
	}
	calculate(range, criteria) {
		if (!range.isReferenceObject()) return ErrorValueObject.create("#VALUE!");
		let _criteria = criteria;
		if (criteria.isReferenceObject()) _criteria = criteria.toArrayValueObject();
		if (_criteria.isArray()) {
			const resultArray = _criteria.mapValue((criteriaObject) => this._handleSingleObject(range, criteriaObject));
			if (resultArray.getRowCount() === 1 && resultArray.getColumnCount() === 1) return resultArray.get(0, 0);
			return resultArray;
		}
		return this._handleSingleObject(range, _criteria);
	}
	_handleSingleObject(range, criteria) {
		const _range = range.toArrayValueObject();
		let resultArrayObject = valueObjectCompare(_range, criteria);
		resultArrayObject = filterSameValueObjectResult(resultArrayObject, _range, criteria);
		const picked = _range.pick(resultArrayObject);
		return this._countA(picked);
	}
	_countA(array) {
		let accumulatorAll = NumberValueObject.create(0);
		array.iterator((valueObject) => {
			if (valueObject == null) return true;
			accumulatorAll = accumulatorAll.plusBy(1);
		});
		return accumulatorAll;
	}
};

