//#region src/functions/statistical/countifs/index.ts
var Countifs = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 2);
		_defineProperty(this, "maxParams", 255);
		_defineProperty(this, "needsReferenceObject", true);
	}
	calculate(...variants) {
		const { isError, errorObject, rangeIsDifferentSize, criteriaMaxRowLength, criteriaMaxColumnLength, variants: _variants } = parsePairedRangeAndCriteria(variants);
		if (isError) return errorObject;
		if (rangeIsDifferentSize) {
			if (criteriaMaxRowLength === 1 && criteriaMaxColumnLength === 1) return ErrorValueObject.create("#VALUE!");
			return expandArrayValueObject(criteriaMaxRowLength, criteriaMaxColumnLength, ErrorValueObject.create("#VALUE!"));
		}
		const results = getPairedRangeAndCriteriaResult(_variants, {
			formulaName: "COUNTIFS",
			maxRowLength: criteriaMaxRowLength,
			maxColumnLength: criteriaMaxColumnLength,
			isNumberSensitive: true
		});
		if (results.length === 1 && results[0].length === 1) return results[0][0];
		return ArrayValueObject.create({
			calculateValueList: results,
			rowCount: results.length,
			columnCount: results[0].length,
			unitId: this.unitId || "",
			sheetId: this.subUnitId || "",
			row: this.row,
			column: this.column
		});
	}
};

