		const array1ColumnCount = array1.isArray() ? array1.getColumnCount() : 1;
		const array2RowCount = array2.isArray() ? array2.getRowCount() : 1;
		const array2ColumnCount = array2.isArray() ? array2.getColumnCount() : 1;
		let _array1 = array1;
		if (array1.isArray() && array1RowCount === 1 && array1ColumnCount === 1) _array1 = array1.get(0, 0);
		if (_array1.isError()) return _array1;
		let _array2 = array2;
		if (array2.isArray() && array2RowCount === 1 && array2ColumnCount === 1) _array2 = array2.get(0, 0);
		if (_array2.isError()) return _array2;
		if (array1RowCount * array1ColumnCount === 1 || array2RowCount * array2ColumnCount === 1) {
			if (_array1.isNull() || _array2.isNull()) return ErrorValueObject.create("#VALUE!");
		}
		if (array1RowCount * array1ColumnCount !== array2RowCount * array2ColumnCount) return ErrorValueObject.create("#N/A");
