//#region src/functions/statistical/devsq/index.ts
var Devsq = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 1);
		_defineProperty(this, "maxParams", 255);
	}
	calculate(...variants) {
		const values = [];
		let sum = 0;
		let noCalculate = true;
		for (let i = 0; i < variants.length; i++) {
			const variant = variants[i];
			if (variant.isArray()) {
				let isError = false;
				let errorObject = ErrorValueObject.create("#VALUE!");
				variant.iterator((valueObject) => {
					const _valueObject = this._handleSingleObject(valueObject);
					if (_valueObject.isError()) {
						isError = true;
						errorObject = _valueObject;
						return false;
					}
					if (_valueObject.isNull()) return true;
					const value = _valueObject.getValue();
					values.push(value);
					sum += value;
					noCalculate = false;
				});
				if (isError) return errorObject;
			} else {
				const _variant = this._handleSingleObject(variant);
				if (_variant.isError()) return _variant;
				if (_variant.isNull()) continue;
				const value = _variant.getValue();
				values.push(value);
				sum += value;
				noCalculate = false;
			}
		}
		if (noCalculate) return ErrorValueObject.create("#NUM!");
		const mean = sum / values.length;
		let result = 0;
		for (let i = 0; i < values.length; i++) result += (values[i] - mean) ** 2;
		return NumberValueObject.create(result);
	}
	_handleSingleObject(variant) {
		if (variant.isError()) return variant;
		if (variant.isNull() || variant.isBoolean()) return NullValueObject.create();
		const value = variant.getValue();
		if (!isRealNum(value)) return NullValueObject.create();
		return NumberValueObject.create(+value);
	}
};

