		const maxColumnLength = Math.max(x.isArray() ? x.getColumnCount() : 1, degFreedom1.isArray() ? degFreedom1.getColumnCount() : 1, degFreedom2.isArray() ? degFreedom2.getColumnCount() : 1, cumulative.isArray() ? cumulative.getColumnCount() : 1);
