//#region src/functions/statistical/fisher/index.ts
var Fisher = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 1);
		_defineProperty(this, "maxParams", 1);
	}
	calculate(x) {
		if (x.isArray()) return x.mapValue((xObject) => this._handleSingleObject(xObject));
		return this._handleSingleObject(x);
	}
	_handleSingleObject(x) {
		const { isError, errorObject, variants } = checkVariantsErrorIsStringToNumber(x);
		if (isError) return errorObject;
		const [xObject] = variants;
		const xValue = xObject.getValue();
		if (xValue <= -1 || xValue >= 1) return ErrorValueObject.create("#NUM!");
		const result = Math.log((1 + xValue) / (1 - xValue)) / 2;
		return NumberValueObject.create(result);
	}
};

