//#region src/functions/statistical/steyx/index.ts
var Steyx = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 2);
		_defineProperty(this, "maxParams", 2);
	}
	calculate(knownYs, knownXs) {
		const knownYsRowCount = knownYs.isArray() ? knownYs.getRowCount() : 1;
		const knownYsColumnCount = knownYs.isArray() ? knownYs.getColumnCount() : 1;
		const knownXsRowCount = knownXs.isArray() ? knownXs.getRowCount() : 1;
		const knownXsColumnCount = knownXs.isArray() ? knownXs.getColumnCount() : 1;
		let _knownYs = knownYs;
		if (knownYs.isArray() && knownYsRowCount === 1 && knownYsColumnCount === 1) _knownYs = knownYs.get(0, 0);
		if (_knownYs.isError()) return _knownYs;
		let _knownXs = knownXs;
		if (knownXs.isArray() && knownXsRowCount === 1 && knownXsColumnCount === 1) _knownXs = knownXs.get(0, 0);
		if (_knownXs.isError()) return _knownXs;
		if (knownYsRowCount * knownYsColumnCount === 1 || knownXsRowCount * knownXsColumnCount === 1) {
			if (_knownYs.isNull() || _knownXs.isNull()) return ErrorValueObject.create("#VALUE!");
		}
		if (knownYsRowCount * knownYsColumnCount !== knownXsRowCount * knownXsColumnCount) return ErrorValueObject.create("#N/A");
		const { isError, errorObject, array1Values, array2Values, noCalculate } = getTwoArrayNumberValues(knownYs, knownXs, knownYsRowCount * knownYsColumnCount, knownYsColumnCount, knownXsColumnCount);
		if (isError) return errorObject;
		if (noCalculate) return ErrorValueObject.create("#DIV/0!");
		return this._getResult(array1Values, array2Values);
	}
	_getResult(knownYs, knownXs) {
		const n = knownYs.length;
		if (n <= 2) return ErrorValueObject.create("#DIV/0!");
		let knownYsSum = 0;
		let knownXsSum = 0;
		for (let i = 0; i < n; i++) {
			knownYsSum += knownYs[i];
			knownXsSum += knownXs[i];
		}
		const knownYsMean = knownYsSum / n;
		const knownXsMean = knownXsSum / n;
		let num = 0;
		let knownYsPowSum = 0;
		let knownXsPowSum = 0;
		for (let i = 0; i < n; i++) {
			num += (knownYs[i] - knownYsMean) * (knownXs[i] - knownXsMean);
			knownYsPowSum += (knownYs[i] - knownYsMean) ** 2;
			knownXsPowSum += (knownXs[i] - knownXsMean) ** 2;
		}
		if (knownXsPowSum === 0) return ErrorValueObject.create("#DIV/0!");
		const result = Math.sqrt((knownYsPowSum - num ** 2 / knownXsPowSum) / (n - 2));
		if (Number.isNaN(result) || !Number.isFinite(result)) return ErrorValueObject.create("#NUM!");
		return NumberValueObject.create(result);
	}
};

