var TDist = class extends BaseFunction {
	constructor(..._args) {
		super(..._args);
		_defineProperty(this, "minParams", 3);
		_defineProperty(this, "maxParams", 3);
	}
	calculate(x, degFreedom, cumulative) {
		const maxRowLength = Math.max(x.isArray() ? x.getRowCount() : 1, degFreedom.isArray() ? degFreedom.getRowCount() : 1, cumulative.isArray() ? cumulative.getRowCount() : 1);
		const maxColumnLength = Math.max(x.isArray() ? x.getColumnCount() : 1, degFreedom.isArray() ? degFreedom.getColumnCount() : 1, cumulative.isArray() ? cumulative.getColumnCount() : 1);
		const xArray = expandArrayValueObject(maxRowLength, maxColumnLength, x, ErrorValueObject.create("#N/A"));
		const degFreedomArray = expandArrayValueObject(maxRowLength, maxColumnLength, degFreedom, ErrorValueObject.create("#N/A"));
		const cumulativeArray = expandArrayValueObject(maxRowLength, maxColumnLength, cumulative, ErrorValueObject.create("#N/A"));
		const resultArray = xArray.mapValue((xObject, rowIndex, columnIndex) => {
			const degFreedomObject = degFreedomArray.get(rowIndex, columnIndex);
			const cumulativeObject = cumulativeArray.get(rowIndex, columnIndex);
			if (xObject.isError()) return xObject;
			if (degFreedomObject.isError()) return degFreedomObject;
			if (cumulativeObject.isError()) return cumulativeObject;
			return this._handleSingleObject(xObject, degFreedomObject, cumulativeObject);
		});
		if (maxRowLength === 1 && maxColumnLength === 1) return resultArray.get(0, 0);
		return resultArray;
	}
	_handleSingleObject(xObject, degFreedomObject, cumulativeObject) {
		const { isError, errorObject, variants } = checkVariantsErrorIsStringToNumber(xObject, degFreedomObject, cumulativeObject);
		if (isError) return errorObject;
		const [_xObject, _degFreedomObject, _cumulativeObject] = variants;
		const xValue = +_xObject.getValue();
		const degFreedomValue = Math.floor(+_degFreedomObject.getValue());
		const cumulativeValue = +_cumulativeObject.getValue();
		if (degFreedomValue < 1) return ErrorValueObject.create("#NUM!");
		let result;
		if (cumulativeValue) result = studentTCDF(xValue, degFreedomValue);
		else result = studentTPDF(xValue, degFreedomValue);
		if (Number.isNaN(result) || !Number.isFinite(result)) return ErrorValueObject.create("#NUM!");
		return NumberValueObject.create(result);
	}
};

